from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

@app.route('/api/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def api_gateway(path):
    token = request.headers.get('Authorization')
    if token is None:
        return jsonify({'error': 'Authorization token is missing'}), 401

    try:
        token = token.split()[1]  # Extract token from "Bearer <token>"
        decoded = jwt.decode(token, options={"verify_signature": False})
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

    user_claims = decoded.get('claims', {})
    
    # Forward request to the backend service
    # Here you would typically use requests or an async library to call your backend.
    # For demonstration, we'll just return the user claims.
    
    return jsonify({'user_claims': user_claims, 'backend_path': path})

if __name__ == '__main__':
    app.run(debug=True)